mapper.select:
SELECT id, user_id, product_id, sku_id, quantity, checked, create_time, update_time
FROM mall_cart
WHERE user_id = #{userId} AND sku_id = #{skuId}

mapper.update:
UPDATE mall_cart
SET quantity = quantity + #{quantity}, update_time = NOW()
WHERE id = #{id}

UPDATE mall_cart
SET quantity = #{quantity}, update_time = NOW()
WHERE id = #{id} AND user_id = #{userId}

UPDATE mall_cart
SET checked = #{checked}, update_time = NOW()
WHERE id = #{id} AND user_id = #{userId}
